import React, { forwardRef, useImperativeHandle, useState, useEffect } from 'react';
import { Box, Alert } from '@mui/material';
import FAWTypography from '../../../FAWTypography';
import FAWLoader from '../../../FAWLoader';
import FAWInput from '../../../FAWInput';
import FAWTextarea from '../../../FAWTextarea';
import FAWErrorBoundary from '../../../errorHandling/FAWErrorBoundary';
import { formFieldStyles } from '../../../shared/styles/formFieldStyles';
import '../styles/refdomain.css';

const RefDomainForm = forwardRef(({
    domainId,
    onSave,
    onCancel,
    initialData,
    saving = false
}, ref) => {
    const [formData, setFormData] = useState({
        Name: '',
        Description: '',
        RefCodeMaxLength: 0,
        Id: 0,
        LockId: 0,
        AgencyId: 0
    });
    const [errors, setErrors] = useState({});
    const [touched, setTouched] = useState({});
    const [loading, setLoading] = useState(false);

    // Initialize form data
    useEffect(() => {
        if (initialData) {
            const newFormData = {
                Name: initialData.Name,
                Description: initialData.Description,
                RefCodeMaxLength: initialData.RefCodeMaxLength,
                Id: initialData.Id,
                LockId: initialData.LockId,
                AgencyId: initialData.AgencyId
            };
            setFormData(newFormData);
        }
    }, [initialData]);

    // Expose methods to parent component
    useImperativeHandle(ref, () => ({
        getFormData: () => formData,
        validateForm: validateForm,
        resetForm: resetForm
    }));

    const validateForm = () => {
        const newErrors = {};

        if (!formData.Name || formData.Name.trim() === '') {
            newErrors.Name = 'Name is required';
        } else if (formData.Name.length > 30) {
            newErrors.Name = 'Name cannot be more than 30 characters';
        }

        if (!formData.Description || formData.Description.trim() === '') {
            newErrors.Description = 'Description is required';
        } else if (formData.Description.length > 1000) {
            newErrors.Description = 'Description cannot be more than 1000 characters';
        }

        if (!formData.RefCodeMaxLength || formData.RefCodeMaxLength < 1 || formData.RefCodeMaxLength > 50) {
            newErrors.RefCodeMaxLength = 'Code Max Length must be between 1 and 50';
        }

        setErrors(newErrors);
        return Object.keys(newErrors).length === 0;
    };

    const resetForm = () => {
        setFormData({
            Name: '',
            Description: '',
            RefCodeMaxLength: 0,
            Id: 0,
            LockId: 0,
            AgencyId: 0
        });
        setErrors({});
        setTouched({});
    };

    const validateField = (fieldName, value) => {
        let error = '';

        switch (fieldName) {
            case 'Name':
                if (!value || value.trim() === '') {
                    error = 'Name is required';
                } else if (value.length > 30) {
                    error = 'Name cannot be more than 30 characters';
                }
                break;
            case 'Description':
                if (!value || value.trim() === '') {
                    error = 'Description is required';
                } else if (value.length > 1000) {
                    error = 'Description cannot be more than 1000 characters';
                }
                break;
            case 'RefCodeMaxLength':
                const numValue = typeof value === 'number' ? value : parseInt(value) || 0;
                if (!numValue || numValue < 1 || numValue > 50) {
                    error = 'Code Max Length must be between 1 and 50';
                }
                break;
            default:
                break;
        }

        return error;
    };

    const handleFieldChange = (fieldName, value) => {
        setFormData(prev => ({
            ...prev,
            [fieldName]: value
        }));

        // Validate field in real-time, but only show error if field has been touched
        const fieldError = validateField(fieldName, value);
        if (touched[fieldName]) {
            // Only show error if field has been blurred (touched)
            setErrors(prev => ({
                ...prev,
                [fieldName]: fieldError
            }));
        } else {
            // Clear error if field hasn't been touched yet
            if (errors[fieldName]) {
                setErrors(prev => ({
                    ...prev,
                    [fieldName]: ''
                }));
            }
        }
    };

    const handleFieldBlur = (fieldName, event) => {
        setTouched(prev => ({
            ...prev,
            [fieldName]: true
        }));

        // Validate field on blur using the latest value from the event or formData
        let value;
        if (event && event.target) {
            // Get value directly from the input event for number fields
            if (fieldName === 'RefCodeMaxLength') {
                value = parseInt(event.target.value) || 0;
            } else {
                value = event.target.value;
            }
        } else {
            value = formData[fieldName];
        }

        const fieldError = validateField(fieldName, value);
        setErrors(prev => ({
            ...prev,
            [fieldName]: fieldError
        }));

        // Also update formData if we got value from event (to ensure sync)
        if (event && event.target && value !== formData[fieldName]) {
            setFormData(prev => ({
                ...prev,
                [fieldName]: value
            }));
        }
    };

    const handleSubmit = (e) => {
        e.preventDefault();
        if (validateForm()) {
            onSave(formData);
        }
    };

    if (loading || saving) {
        return (
            <Box sx={{ p: 3 }}>
                <FAWLoader label="Loading form..." />
                {saving && (
                    <Box sx={{
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'center',
                        mt: 2,
                        gap: 1
                    }}>
                        <FAWLoader size={20} label="" />
                        <FAWTypography variant="body2" color="primary" sx={{ fontWeight: 'bold' }}>
                            Saving domain...
                        </FAWTypography>
                    </Box>
                )}
            </Box>
        );
    }

    return (
        <FAWErrorBoundary
            title="Form Error"
            message="An error occurred while rendering the domain form. Please try again."
            showDetails={false}
            onError={(error, errorInfo) => {
                console.error('RefDomainForm Error:', error, errorInfo);
            }}
        >
            <Box className="refdomain-form-container" sx={{ p: 3 }}>
                <form className="refdomain-form" onSubmit={(e) => e.preventDefault()}>
                    <Box className="refdomain-form-fields" sx={{ display: 'flex', flexDirection: 'column', gap: 3 }}>
                        {/* Name Input */}
                        <FAWInput
                            className="refdomain-form-name-input"
                            id="domain-name"
                            label="Name"
                            placeholder="Enter domain name"
                            value={formData.Name}
                            onChange={(e) => handleFieldChange('Name', e.target.value)}
                            onBlur={(e) => handleFieldBlur('Name', e)}
                            error={!!errors.Name}
                            helperText={errors.Name}
                            variant="outlined"
                            fullWidth
                            required
                            disabled={domainId && domainId !== 0} // Disable for existing domains
                            inputProps={{ maxLength: 30 }}
                            sx={formFieldStyles.inputWhite}
                        />

                        {/* Description Textarea */}
                        <FAWTextarea
                            className="refdomain-form-description-textarea"
                            id="domain-description"
                            label="Description"
                            placeholder="Enter domain description"
                            value={formData.Description}
                            onChange={(e) => handleFieldChange('Description', e.target.value)}
                            onBlur={(e) => handleFieldBlur('Description', e)}
                            error={!!errors.Description}
                            helperText={errors.Description}
                            rows={3}
                            variant="outlined"
                            fullWidth
                            required
                            inputProps={{ maxLength: 1000 }}
                            sx={formFieldStyles.textareaWhite}
                        />

                        {/* Code Max Length Input */}
                        <FAWInput
                            className="refdomain-form-codemaxlength-input"
                            id="domain-codemaxlength"
                            label="Code Max Length"
                            placeholder="Enter maximum code length"
                            type="number"
                            value={formData.RefCodeMaxLength}
                            onChange={(e) => handleFieldChange('RefCodeMaxLength', parseInt(e.target.value) || 0)}
                            onBlur={(e) => handleFieldBlur('RefCodeMaxLength', e)}
                            error={!!errors.RefCodeMaxLength}
                            helperText={errors.RefCodeMaxLength}
                            variant="outlined"
                            fullWidth
                            required
                            inputProps={{ min: 1, max: 50 }}
                            sx={formFieldStyles.inputWhite}
                        />

                        {/* Hidden Fields */}
                        <input type="hidden" name="Id" value={formData.Id} />
                        <input type="hidden" name="LockId" value={formData.LockId} />
                        <input type="hidden" name="AgencyId" value={formData.AgencyId} />
                    </Box>
                </form>
            </Box>
        </FAWErrorBoundary>
    );
});

RefDomainForm.displayName = 'RefDomainForm';

export default RefDomainForm;
