import React, { useCallback, useMemo, useEffect } from 'react';
import { 
  Box, 
  Grid, 
  Paper, 
  IconButton,
  Tooltip
} from '@mui/material';
import FAWTypography from '../../../FAWTypography';
import FAWSkeleton from '../../../FAWSkeleton';
import FAWLoader from '../../../FAWLoader';
import { Search as SearchIcon, Settings as SettingsIcon } from '@mui/icons-material';
import FAWDrawer from '../../../FAWDrawer';
import FAWToast from '../../../FAWToast';
import FAWErrorBoundary from '../../../errorHandling/FAWErrorBoundary';
import FAWModal from '../../../FAWModal';
import RefDomainForm from './RefDomainForm';
import { useRefDomainManagerState } from '../hooks/useRefDomainManagerState';
import { useRefDomainManagerHandlers } from '../hooks/useRefDomainManagerHandlers';
import '../../css/workflow.css';
import '../styles/refdomain.css';

const RefDomainManager = ({ domainId, initialData, onSuccess, onCancel, existingNames }) => {
  // Clean up URL query parameters on mount
  useEffect(() => {
    const urlParams = new URLSearchParams(window.location.search);
    const hasUnwantedParams = urlParams.has('Type') || urlParams.has('Message') || urlParams.has('IsDismissable');
    
    if (hasUnwantedParams) {
      // Remove unwanted query parameters
      urlParams.delete('Type');
      urlParams.delete('Message');
      urlParams.delete('IsDismissable');
      
      // Update URL without the unwanted parameters
      const newUrl = window.location.pathname + (urlParams.toString() ? '?' + urlParams.toString() : '');
      window.history.replaceState({}, '', newUrl);
    }
  }, []);
  // Use custom hooks for state management and handlers
  const state = useRefDomainManagerState({ domainId, initialData, onSuccess, onCancel });
  const handlers = useRefDomainManagerHandlers({
    domainId,
    onSuccess,
    onCancel,
    formRef: state.formRef,
    setSaving: state.setSaving,
    setToast: state.setToast,
    setDrawerOpen: state.setDrawerOpen,
    setError: state.setError,
    setConfirmationDialog: state.setConfirmationDialog,
    existingNames
  });

  // Determine if we should show drawer
  const isNewDomain = !domainId || domainId === 0;
  const showDrawer = true; // Always show drawer when component is mounted

  // Define drawer actions with useMemo to prevent unnecessary re-renders
  const drawerActions = useMemo(() => [
    {
      text: 'Cancel',
      variant: 'outlined',
      onClick: handlers.handleCancel,
      disabled: state.saving,
      handlerType: 'custom' // Bypass form submission for custom handlers
    },
    {
      text: state.saving ? 'Saving...' : 'Save',
      variant: 'contained',
      color: 'primary',
      onClick: handlers.handleSaveClick,
      disabled: state.saving,
      handlerType: 'custom', // Bypass form submission for custom handlers
      componentType: 'refdomain' // Special identifier for refdomain
    }
  ], [handlers.handleCancel, handlers.handleSaveClick, state.saving]);

  // Memoize confirmation dialog content and actions to prevent unnecessary re-renders
  const confirmationContent = useMemo(() => (
    <Box sx={{ p: 0 }}>
      <FAWTypography variant="body1" sx={{ whiteSpace: 'pre-line' }}>
        {state.confirmationDialog.message}
      </FAWTypography>
    </Box>
  ), [state.confirmationDialog.message]);

  const confirmationActions = useMemo(() => [
    {
      label: state.confirmationDialog.confirmText || 'Continue',
      onClick: state.confirmationDialog.onCancel,
      variant: 'outlined',
      color: 'primary'
    },
    {
      label: state.confirmationDialog.cancelText || 'Cancel',
      onClick: state.confirmationDialog.onConfirm,
      variant: 'contained',
      color: state.confirmationDialog.severity === 'error' ? 'error' : 'primary'
    }
  ], [
    state.confirmationDialog.cancelText,
    state.confirmationDialog.confirmText,
    state.confirmationDialog.onCancel,
    state.confirmationDialog.onConfirm,
    state.confirmationDialog.severity
  ]);

  return (
    <FAWErrorBoundary
      title="RefDomain Error"
      message="An error occurred while loading the reference domain. Please try again or contact support if the problem persists."
      showDetails={true}
      onError={(error, errorInfo) => {
        console.error('RefDomainManager Error:', error, errorInfo);
      }}
      onReportError={(error) => {
        // Error reported by user
      }}
    >
      <Box className="refdomain-manager-container">
        {/* Atlas Toast for notifications */}
        <FAWToast 
          className="refdomain-manager-toast"
          open={state.toast.open} 
          message={state.toast.message} 
          type={state.toast.type} 
          duration={state.toast.duration}
          onClose={handlers.handleToastClose} 
        />

        {/* Confirmation Dialog */}
        <FAWModal
          open={state.confirmationDialog.open}
          title={state.confirmationDialog.title}
          content={confirmationContent}
          actions={confirmationActions}
          onClose={state.confirmationDialog.onCancel}
        />

        {/* Main Drawer - Contains the form for creating/editing */}
        <FAWDrawer
          className="refdomain-manager-drawer"
          open={showDrawer}
          onClose={handlers.handleCloseDrawer}
          title={isNewDomain ? 'Add New Domain' : `Edit Reference Domain${state.initialData?.Name ? ` - ${state.initialData.Name}` : ''}`}
          width={600}
          anchor="right"
          variant="temporary"
          showCloseButton={true}
          showHeader={true}
          customFooter={true}
          actions={drawerActions}
        >
          <Box sx={{ position: 'relative', height: '100%' }}>
            {/* Saving overlay */}
            {state.saving && (
              <Box
                sx={{
                  position: 'absolute',
                  top: 0,
                  left: 0,
                  right: 0,
                  bottom: 0,
                  backgroundColor: 'rgba(255, 255, 255, 0.8)',
                  display: 'flex',
                  justifyContent: 'center',
                  alignItems: 'center',
                  zIndex: 10,
                  backdropFilter: 'blur(2px)'
                }}
              >
                <FAWLoader size={40} label="Saving..." />
              </Box>
            )}
            
            {state.loading ? (
              <Box className="refdomain-manager-drawer-loading" sx={{ p: 3 }}>
                <FAWSkeleton variant="form" />
              </Box>
            ) : (
              <RefDomainForm
                ref={state.formRef}
                domainId={domainId}
                onSave={handlers.handleSaveClick}
                onCancel={handlers.handleCancel}
                initialData={state.initialData}
                saving={state.saving}
              />
            )}
          </Box>
        </FAWDrawer>
      </Box>
    </FAWErrorBoundary>
  );
};

export default RefDomainManager;
