import { useCallback } from 'react';

/**
 * Custom hook for managing RefDomainManager handlers
 * Extracts all handler logic to make the component more modular
 */
export const useRefDomainManagerHandlers = ({
  domainId,
  onSuccess,
  onCancel,
  formRef,
  setSaving,
  setToast,
  setDrawerOpen,
  setError,
  setConfirmationDialog,
  existingNames = []
}) => {

  const handleSaveClick = useCallback(async (formData) => {
    if (!formRef.current) {
      console.error('Form ref not available');
      return;
    }

    try {
      setSaving(true);
      setError(null);

      // Validate form
      const isValid = formRef.current.validateForm();
      if (!isValid) {
        // Validation failed - return without showing toast message
        setSaving(false);
        return;
      }

      // Get form data
      const data = formRef.current.getFormData();
      
      // Ensure all required fields are included
      const formData = {
        Name: data.Name,
        Description: data.Description,
        RefCodeMaxLength: data.RefCodeMaxLength,
        Id: data.Id,
        LockId: data.LockId,
        AgencyId: data.AgencyId
      };
      
      // Client-side duplicate check for new domains only
      if (!formData.Id || formData.Id === 0) {
        const nameLower = (formData.Name || '').trim().toLowerCase();
        const exists = Array.isArray(existingNames) && existingNames.some(n => (n || '').trim().toLowerCase() === nameLower);
        if (exists) {
          setToast({
            open: true,
            message: 'Domain already exists. Please use a different name.',
            type: 'error',
            duration: 5000
          });
          setSaving(false);
          return; // Do not submit
        }
      }
      
      // Create form for submission
      const form = document.createElement('form');
      form.method = 'POST';
      form.action = '/RefDomain/SaveRefDomain';
      
      // Add anti-forgery token
      const token = document.querySelector('input[name="__RequestVerificationToken"]');
      if (token) {
        const tokenClone = token.cloneNode(true);
        form.appendChild(tokenClone);
      }

      // Add form data
      Object.keys(formData).forEach(key => {
        const input = document.createElement('input');
        input.type = 'hidden';
        input.name = `CurrentRefDomain.${key}`;
        input.value = formData[key] !== null && formData[key] !== undefined ? formData[key] : '';
        form.appendChild(input);
      });

      // Submit form
      document.body.appendChild(form);
      form.submit();

    } catch (err) {
      console.error('Error saving domain:', err);
      setError(err.message || 'Failed to save domain');
      setToast({
        open: true,
        message: 'Failed to save domain',
        type: 'error',
        duration: 5000
      });
    } finally {
      setSaving(false);
    }
  }, [formRef, setSaving, setToast, setError, existingNames]);

  const handleCancel = useCallback(() => {
    setConfirmationDialog({
      open: true,
      title: 'Discard Changes',
      message: 'Are you sure you want to discard changes?\n\nIf you discard, all information related to the domain you are currently creating will be lost.',
      confirmText: 'No, Continue',
      cancelText: 'Yes, Discard',
      severity: 'warning',
      onConfirm: () => {
        setConfirmationDialog(prev => ({ ...prev, open: false }));
        if (onCancel) {
          onCancel();
        } else {
          // Default behavior - redirect to index
          window.location.href = '/RefDomain';
        }
      },
      onCancel: () => {
        setConfirmationDialog(prev => ({ ...prev, open: false }));
      }
    });
  }, [onCancel, setConfirmationDialog]);

  const handleCloseDrawer = useCallback(() => {
    setDrawerOpen(false);
    if (onCancel) {
      onCancel();
    } else {
      // Default behavior - redirect to index
      window.location.href = '/RefDomain';
    }
  }, [setDrawerOpen, onCancel]);

  const handleToastClose = useCallback(() => {
    setToast(prev => ({ ...prev, open: false }));
  }, [setToast]);

  return {
    handleSaveClick,
    handleCancel,
    handleCloseDrawer,
    handleToastClose
  };
};
