import { useState, useEffect, useCallback, useRef } from 'react';

/**
 * Custom hook for managing RefDomainManager state
 * Extracts all state management logic to make the component more modular
 */
export const useRefDomainManagerState = ({ domainId, initialData: propsInitialData, onSuccess, onCancel }) => {
  // Core state - Initialize drawer based on whether this is a new domain
  const [drawerOpen, setDrawerOpen] = useState(!domainId || domainId === 0);
  const [toast, setToast] = useState({ open: false, message: '', type: 'info', duration: 3000 });
  const [saving, setSaving] = useState(false);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  
  // Form and data state
  const formRef = useRef(null);
  const [initialData, setInitialData] = useState(null);
  
  // Confirmation dialog state
  const [confirmationDialog, setConfirmationDialog] = useState({
    open: false,
    title: '',
    message: '',
    onConfirm: null,
    onCancel: null,
    confirmText: 'Yes',
    cancelText: 'No',
    severity: 'warning'
  });

  // Auto-open drawer when component mounts (only for new domains)
  useEffect(() => {
    // Only auto-open drawer for new domains (domainId is 0 or null)
    const isNewDomain = !domainId || domainId === 0;
    setDrawerOpen(isNewDomain);
  }, [domainId]);

  // Load data function
  const loadData = useCallback(async () => {
    if (!domainId || domainId === 0) {
      // New domain - set default values
      setInitialData({
        Name: '',
        Description: '',
        RefCodeMaxLength: 0,
        Id: 0,
        LockId: 0,
        AgencyId: 0
      });
      setLoading(false);
      return;
    }

    try {
      setLoading(true);
      setError(null);
      
      // Use provided initialData if available, otherwise set default values
      if (propsInitialData) {
        setInitialData(propsInitialData);
      } else {
        // Fallback to default values if no initialData provided
        setInitialData({
          Name: '',
          Description: '',
          RefCodeMaxLength: 0,
          Id: domainId,
          LockId: 0,
          AgencyId: 0
        });
      }
      
    } catch (err) {
      console.error('Error loading domain data:', err);
      setError(err.message || 'Failed to load domain data');
      setToast({
        open: true,
        message: 'Failed to load domain data',
        type: 'error',
        duration: 5000
      });
    } finally {
      setLoading(false);
    }
  }, [domainId, propsInitialData]);

  // Load data on mount
  useEffect(() => {
    loadData();
  }, [loadData]);

  return {
    // Core state
    drawerOpen,
    setDrawerOpen,
    toast,
    setToast,
    saving,
    setSaving,
    loading,
    setLoading,
    error,
    setError,
    
    // Form state
    formRef,
    initialData,
    setInitialData,
    
    // Dialog state
    confirmationDialog,
    setConfirmationDialog,
    
    // Actions
    loadData
  };
};
